THE RISK:
{
 "id": "global-framework-forecloses-large-operator-cell",
 "title": "Global framework agreements foreclose the large-operator channel — the venture's declared first buyer — from a CE entry point",
 "narrative": "The model gives large operators 0.40 of buyer spend, and the venture plans to sell to them first. But hyperscalers and pan-European colos (Equinix, Digital Realty — exactly the accounts on Vertiv's published major-customer list) qualify rack-PDU vendors on global framework agreements and approved-vendor lists negotiated at HQ on multi-year cycles. That spend is not addressable from a Central European regional sales motion in a 12-month window; it is not 'ours to win slowly', it is contractually and organizationally elsewhere. The 0.40 itself rests on a misread company-level order-mix statistic, not any channel data. The venture's GTM points at the one cell of the cube that is structurally closed to it.",
 "category": "competitive",
 "targetNodes": [
  "cust.operator-large"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "Large-operator PDU procurement runs through global AVLs and framework agreements: Vertiv's named major customers are the global hyperscale/colo/telecom accounts, and industrial suppliers report data-center demand concentrating in exactly these buyers",
   "refs": [
    "digest:cust-mix#c9",
    "digest:cust-mix#c0"
   ]
  },
  {
   "step": "propagation",
   "text": "The 0.40 large-operator share has no channel evidence behind it — its sole datapoint is one supplier's 30%-of-orders stat, and no source publishes any numeric buyer-channel split — so the model cannot distinguish 'large operators buy 40% of PDUs' from 'large operators buy 40% of PDUs via global frameworks a CE entrant cannot bid into'",
   "refs": [
    "ledger:cust.operator-large",
    "digest:cust-mix#c0"
   ]
  },
  {
   "step": "model-impact",
   "text": "For this venture's reachable scope, the large-operator cell is foreclosed rather than merely competitive; the declared first-buyer strategy targets it anyway, so SAM and Year-1 pipeline are built on a cell the funnel counts but the venture cannot access",
   "refs": [
    "profile:Who is the primary buyer you'll sell through first?",
    "ledger:cust.operator-large"
   ]
  }
 ],
 "whyMissable": "'Sell to large operators first' looks like the conservative, high-credibility move — big logos, big volumes. The buyer-mix node even carries a wide band, giving the impression the uncertainty is priced. What the band cannot express is reachability: the share may be exactly 0.40 and still be zero for a regional entrant, because the purchase decision physically happens in another region under an existing framework.",
 "expectedObviousness": "medium",
 "falsifier": "Two or more CE-region large operators (hyperscale or pan-European colo) confirming country-level PDU sourcing authority and a documented case of a new vendor entering their AVL via a regional pilot within 12 months.",
 "likelihood": {
  "value": 0.42,
  "rationale": "Global AVL procurement at hyperscale/pan-European colo accounts is well documented qualitatively; uncertainty is whether CE country organizations retain any local sourcing discretion for retrofit and expansion projects. [evidence revision: The trigger (global-framework procurement at the very top accounts) is strongly corroborated, but the falsifier direction gained partial support: regional CE colos (Greenergy) and European operators do procure PDUs through local partners and switch vendors, showing the 'large-operator' cell is not uniformly foreclosed for the regionally-addressable operators the model likely bundles in. No source shows a hyperscale account opened via a regional pilot, so the mechanism holds at the apex but weakens across the segment. Net small downward adjustment.]",
  "basis": "evidence",
  "revisedFrom": 0.45
 },
 "perturbation": [
  {
   "nodeId": "cust.operator-large",
   "op": "exclude",
   "note": "Foreclosure, not shrinkage: the large-operator cell exists in the market but is unavailable to a CE regional entrant in the model's horizon"
  }
 ],
 "indicators": [
  {
   "signal": "Vendor-qualification and supplier-registration requirements for rack power at pan-European colos",
   "where": "Equinix and Digital Realty supplier/procurement portals; framework tender notices on TED (tenders.europa.eu) for DC fit-outs",
   "threshold": "PDU category listed only under global framework agreements with no regional qualification path",
   "updates": "increases"
  },
  {
   "signal": "Where incumbent PDU wins at large accounts are booked",
   "where": "Vertiv and Schneider quarterly earnings calls, commentary on hyperscale framework awards",
   "threshold": "Rack-power growth attributed predominantly to global framework expansions rather than regional project wins",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Run three structured CE operator/distributor procurement interviews specifically probing local vs HQ sourcing authority for rack PDUs (the node's own promotion path)",
   "type": "information",
   "voiNodeId": "cust.operator-large",
   "note": "Directly tests reachability of the 0.40 cell before GTM spend commits to it"
  },
  {
   "action": "Open a parallel OEM/white-label route via rack integrators, which is documented as an existing channel and does not require AVL entry",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Digipower/GETEK-style OEM supply reaches large-operator racks without winning the framework"
  }
 ],
 "evidenceStatus": "contested",
 "evidence": [
  {
   "title": "Vertiv Partner Program EMEA — Major Customers list",
   "sourceType": "industry-report",
   "publisher": "Vertiv",
   "date": null,
   "excerpt": "MAJOR CUSTOMERS Alibaba, Alstom, America Movil, AT&T, China Mobile, Equinix, Ericsson, Reliance, Siemens, Telefonica, Tencent, Verizon and Vodafone",
   "url": "https://www.vertiv.com/49858a/globalassets/documents/brochures/vertiv-partner-program-emea-2024-en.pdf",
   "attached": true
  },
  {
   "title": "Global Data Center Supplier Risk Management (Google/Achilles)",
   "sourceType": "industry-report",
   "publisher": "Achilles",
   "date": "2026-03-06",
   "excerpt": "Google's Data Center Construction Program team uses Achilles to scale its global data center construction program... streamlines supplier intake, prequalification, and risk visibility, enabling faster, data-driven procurement decisions",
   "url": "https://www.achilles.com/industry-insights/google/",
   "attached": true
  },
  {
   "title": "Greenergy and A-Kaabel deploy Vertiv rack PDUs in Estonia",
   "sourceType": "industry-report",
   "publisher": "Vertiv",
   "date": null,
   "excerpt": "Now Estonia's leading colocation provider, Greenergy targets HPC and AI customers with IT loads exceeding 10 MW... Supporting this evolution is A-Kaabel OÜ... an authorized sales and service partner for Vertiv in Estonia.",
   "url": "https://www.vertiv.com/48ebb0/globalassets/documents/case-studies/vertiv-greenergy-cs-en-emea-web.pdf",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://www.vertiv.com/49858a/globalassets/documents/brochures/vertiv-partner-program-emea-2024-en.pdf",
   "stance": "supports",
   "quote": "MAJOR CUSTOMERS Alibaba, Alstom, America Movil, AT&T, China Mobile, Equinix, Ericsson, Reliance, Siemens, Telefonica, Tencent, Verizon and Vodafone"
  },
  {
   "url": "https://investors.generac.com/news-releases/news-release-details/generac-signs-global-supply-agreement-leading-hyperscale-data",
   "stance": "supports",
   "quote": "today announced it has signed a global supply agreement with a leading hyperscale data center operator to supply backup power generators for the company's data center infrastructure"
  },
  {
   "url": "https://www.achilles.com/industry-insights/google/",
   "stance": "supports",
   "quote": "Google's Data Center Construction Program team uses Achilles to scale its global data center construction program to deliver consistent supplier risk management. The platform streamlines supplier intake, prequalification, and risk visibility"
  },
  {
   "url": "https://www.vertiv.com/48ebb0/globalassets/documents/case-studies/vertiv-greenergy-cs-en-emea-web.pdf",
   "stance": "contradicts",
   "quote": "Now Estonia's leading colocation provider, Greenergy targets HPC and AI customers with IT loads exceeding 10 MW, prompting upgrades to its power and liquid cooling infrastructure. Supporting this evolution is A-Kaabel OÜ, an established technology company in Estonia delivering comprehensive design, construction, and maintenance"
  },
  {
   "url": "https://advanceddatacentre.com/case-studies/european-bank-pdu-migration/",
   "stance": "contradicts",
   "quote": "When a leading European bank decided to change its intelligent PDU supplier, the challenge extended far beyond hardware replacement."
  }
 ]
}

